  1→/**
  2→ * Backend Process Manager
  3→ *
  4→ * Spawns the Node.js backend as a child process using Electron's built-in
  5→ * Node runtime (ELECTRON_RUN_AS_NODE=1) in both dev and production.
  6→ * This ensures native modules (better-sqlite3, node-pty) compiled by
  7→ * electron-builder always match the runtime ABI — no system Node required.
  8→ *
  9→ * Parses the dynamic port from stdout, generates an auth token, and handles
 10→ * exit/restart with exponential backoff.
 11→ */
 12→
 13→import { spawn, type ChildProcess } from "child_process";
 14→import { join } from "path";
 15→import { writeFileSync } from "fs";
 16→import { app, BrowserWindow } from "electron";
 17→import crypto from "crypto";
 18→
 19→// Chrome DevTools Protocol port for agent-browser CDP integration.
 20→// Shared with index.ts (remote-debugging-port switch) so the Electron
 21→// debug port and the CDP_PORT env var passed to the backend always match.
 22→export const CDP_PORT = "19222";
 23→
 24→let backendProcess: ChildProcess | null = null;
 25→let isQuitting = false;
 26→let restartAttempt = 0;
 27→let restartTimer: ReturnType<typeof setTimeout> | null = null;
 28→const MAX_RESTART_ATTEMPTS = 5;
 29→const STARTUP_TIMEOUT_MS = 30_000;
 30→
 31→export async function spawnBackend(): Promise<{ port: number; authToken: string }> {
 32→  const authToken = crypto.randomBytes(24).toString("hex");
 33→  const projectRoot = join(__dirname, "../..");
 34→  // Always use Electron's Node binary for the backend process.
 35→  // electron-builder install-app-deps compiles native modules (better-sqlite3, node-pty)
 36→  // against Electron's Node ABI. Using system node would cause MODULE_VERSION mismatch.
 37→  const backendRuntime = process.execPath;
 38→
 39→  // Resolve backend entry point
 40→  // Production: bundled CJS file (no tsx dependency needed)
 41→  // Development: server.cjs bootstraps tsx for live TypeScript
 42→  const backendEntry = app.isPackaged
 43→    ? join(process.resourcesPath, "backend", "server.bundled.cjs")
 44→    : join(projectRoot, "apps/backend/server.cjs");
 45→
 46→  // Database lives in Electron's userData dir (~/Library/Application Support/Deus/).
 47→  const dbPath = join(app.getPath("userData"), "deus.db");
 48→
 49→  // Agent-server bundle path
 50→  const agentServerPath = app.isPackaged
 51→    ? join(process.resourcesPath, "bin", "index.bundled.cjs")
 52→    : join(projectRoot, "apps/agent-server/dist/index.bundled.cjs");
 53→
 54→  // Notebook server bundle path
 55→  const notebookPath = app.isPackaged
 56→    ? join(process.resourcesPath, "bin", "notebook-server.bundled.cjs")
 57→    : join(projectRoot, "packages/mcp-notebook/dist/notebook-server.bundled.cjs");
 58→
 59→  return new Promise((resolve, reject) => {
 60→    backendProcess = spawn(backendRuntime, [backendEntry], {
 61→      cwd: app.isPackaged ? process.resourcesPath : join(projectRoot, "apps/backend"),
 62→      env: {
 63→        ...process.env,
 64→        ELECTRON_RUN_AS_NODE: "1",
 65→        DATABASE_PATH: dbPath,
 66→        AGENT_SERVER_BUNDLE_PATH: agentServerPath,
 67→        NOTEBOOK_SERVER_BUNDLE_PATH: notebookPath,
 68→        AUTH_TOKEN: authToken,
 69→        PORT: "0", // Dynamic port allocation
 70→        CDP_PORT, // Chrome DevTools Protocol port for agent-browser integration
 71→      },
 72→      stdio: ["ignore", "pipe", "pipe"],
 73→    });
 74→
 75→    let resolved = false;
 76→    let stdoutBuffer = "";
 77→
 78→    // Parse port from stdout
 79→    backendProcess.stdout?.on("data", (data: Buffer) => {
 80→      stdoutBuffer += data.toString();
 81→      const lines = stdoutBuffer.split("\n");
 82→      stdoutBuffer = lines.pop() ?? ""; // Keep incomplete last line in buffer
 83→      for (const line of lines) {
 84→        const trimmed = line.trim();
 85→        if (!trimmed) continue;
 86→
 87→        // Log backend stdout in dev mode
 88→        if (!app.isPackaged) {
 89→          console.log("[backend]", trimmed);
 90→        }
 91→
 92→        const portMatch = trimmed.match(/^\[BACKEND_PORT\](\d+)$/);
 93→        if (portMatch && !resolved) {
 94→          resolved = true;
 95→          restartAttempt = 0;
 96→          const port = parseInt(portMatch[1], 10);
 97→
 98→          // Write port to temp file so Chrome tabs (without electronAPI) can discover it.
 99→          // The Vite dev server serves this via middleware in electron.vite.config.ts.
100→          if (!app.isPackaged) {
101→            try {
102→              const portFile = join(app.getPath("temp"), "deus-backend-port");
103→              writeFileSync(portFile, String(port));
104→            } catch {
105→              // Non-critical — only used for Chrome tab port discovery
106→            }
107→          }
108→
109→          resolve({ port, authToken });
110→        }
111→
112→        // Relay workspace init progress events to the renderer.
113→        // Backend emits: DEUS_WORKSPACE_PROGRESS:{"workspaceId":"...","step":"...","label":"..."}
114→        // We parse the JSON and forward it as an IPC event to the renderer.
115→        // SYNC: Event name must match shared/events.ts (AppEventMap["workspace:progress"])
116→        if (trimmed.startsWith("DEUS_WORKSPACE_PROGRESS:")) {
117→          const jsonStr = trimmed.slice("DEUS_WORKSPACE_PROGRESS:".length);
118→          try {
119→            const payload = JSON.parse(jsonStr);
