 1→/**
 2→ * Analytics — thin PostHog wrapper with consent gating.
 3→ *
 4→ * Module-level boolean (_enabled) is synced by useAnalyticsConsent() on app boot.
 5→ * PostHog's opt_out_capturing acts as a second gate at the network layer.
 6→ * All calls are fire-and-forget — analytics must never crash the app.
 7→ */
 8→import posthog from "posthog-js";
 9→import type { AnalyticsEventMap, AnalyticsEvent } from "./events";
10→
11→let _enabled = false;
12→
13→/**
14→ * Sync consent state. Called by useAnalyticsConsent and the settings toggle.
15→ * Tracking starts disabled and is enabled on first consent sync.
16→ */
17→export function setAnalyticsEnabled(enabled: boolean): void {
18→  _enabled = enabled;
19→  try {
20→    if (enabled) {
21→      posthog.opt_in_capturing();
22→    } else {
23→      posthog.opt_out_capturing();
24→    }
25→  } catch {
26→    // Silent — PostHog may not be fully initialized yet
27→  }
28→}
29→
30→/** Track a typed event. No-op when analytics disabled. */
31→export function track<E extends AnalyticsEvent>(
32→  event: E,
33→  ...args: AnalyticsEventMap[E] extends Record<string, never>
34→    ? []
35→    : [properties: AnalyticsEventMap[E]]
36→): void {
37→  if (!_enabled) return;
38→  try {
39→    posthog.capture(event, args[0] as Record<string, unknown> | undefined);
40→  } catch {
41→    // Analytics must never crash the app
42→  }
43→}
