45→/** Identify user with non-PII traits for cohort analysis. */
46→export function identifyUser(traits?: Record<string, unknown>): void {
47→  if (!_enabled) return;
48→  try {
49→    posthog.setPersonProperties(traits ?? {});
50→  } catch {
51→    // Silent
52→  }
53→}
