 1→import type { ErrorInfo } from "react";
 2→import * as Sentry from "@sentry/react";
 3→import { track } from "@/platform/analytics";
 4→type ErrorContext = {
 5→  source?: string;
 6→  action?: string;
 7→  tags?: Record<string, string | number | boolean>;
 8→  extra?: Record<string, unknown>;
 9→};
10→
11→function safeStringify(value: unknown): string {
12→  try {
13→    return JSON.stringify(value);
14→  } catch {
15→    return String(value);
16→  }
17→}
18→
19→export function normalizeError(error: unknown): Error {
20→  if (error instanceof Error) {
21→    return error;
22→  }
23→
24→  if (typeof error === "string") {
25→    return new Error(error);
26→  }
27→
28→  if (error && typeof error === "object") {
29→    const maybeMessage = (error as { message?: unknown }).message;
30→    if (typeof maybeMessage === "string") {
31→      return new Error(maybeMessage);
32→    }
33→  }
34→
35→  return new Error(safeStringify(error));
36→}
37→
38→export function reportError(error: unknown, context: ErrorContext = {}): Error {
39→  const normalized = normalizeError(error);
40→  const payload = {
41→    ...context,
42→    error: {
43→      name: normalized.name,
44→      message: normalized.message,
45→      stack: normalized.stack,
46→    },
47→  };
48→
49→  console.error("[Error]", payload);
50→
51→  Sentry.captureException(normalized, {
52→    tags: context.tags,
53→    extra: { ...context.extra, source: context.source, action: context.action },
54→  });
55→
56→  // Track errors in PostHog for reliability monitoring
57→  track("error_occurred", {
58→    source: context.source ?? "unknown",
59→    error_message: normalized.message.substring(0, 200),
60→  });
61→
62→  return normalized;
63→}
64→
65→/** Shared error handler for React error boundaries -- reports + stores component stack. */
66→export function createBoundaryErrorHandler(source: string) {
67→  return (error: unknown, info: ErrorInfo) => {
68→    reportError(error, {
69→      source,
70→      extra: { componentStack: info.componentStack ?? undefined },
71→    });
72→    (window as { __APP_LAST_COMPONENT_STACK__?: string }).__APP_LAST_COMPONENT_STACK__ =
73→      info.componentStack ?? undefined;
74→  };
75→}
