  1→/**
  2→ * Analytics Event Taxonomy — single source of truth for all tracked events.
  3→ *
  4→ * DATA MODEL DECISIONS:
  5→ *
  6→ *   Naming:  {object}_{action} in snake_case, past tense.
  7→ *            object = domain noun (workspace, session, repo)
  8→ *            action = past-tense verb (created, sent, opened)
  9→ *            This reads naturally in PostHog queries: "show me all workspace_created".
 10→ *
 11→ *   Shape:   Flat records. No nesting. PostHog flattens nested objects anyway,
 12→ *            so nesting just adds indirection with zero analytical benefit.
 13→ *            Optional fields use `?` — callers omit when context is unavailable.
 14→ *
 15→ *   Context: Session context (model, agent_type) lives on events where it's
 16→ *            analytically useful — message_sent, turn_completed, session_created.
 17→ *            NOT on every event. PostHog person properties carry the "current"
 18→ *            provider/theme/plan. Event properties carry per-action context.
 19→ *            Duplicating session context onto unrelated events (diff_viewed, etc.)
 20→ *            just inflates payload size with data PostHog already has via person props.
 21→ *
 22→ *   PII:     Properties are structural metadata only — never message content,
 23→ *            file paths, API keys, or free-text user input.
 24→ *
 25→ * TYPE SYSTEM INVARIANTS:
 26→ *   1. Every event key is a literal — no stringly-typed track() calls compile.
 27→ *   2. Per-event property types are exact — extra/wrong fields are type errors.
 28→ *   3. No-property events use Record<string, never> — track() accepts zero args.
 29→ *   4. AnalyticsEvent = keyof AnalyticsEventMap — the map IS the schema.
 30→ *   5. WithWorkspace / WithSession fragments enforce consistent field names
 31→ *      across related events (no "workspace_id" vs "workspaceId" drift).
 32→ *
 33→ * ADDING A NEW EVENT:
 34→ *   1. Add a key + property type to AnalyticsEventMap below.
 35→ *   2. Call track("your_event", { ...props }) at the call site.
 36→ *   That's it. TypeScript enforces correctness — no registration step.
 37→ */
 38→
 39→// ─── Property Fragments ─────────────────────────────────────────────────────
 40→// Composition > inheritance. These enforce consistent field naming across
 41→// related events without a class hierarchy. Internal only — not exported.
 42→
 43→type WithWorkspace = { workspace_id: string };
 44→type WithSession = { session_id: string };
 45→
 46→// ─── Event Map ──────────────────────────────────────────────────────────────
 47→
 48→export type AnalyticsEventMap = {
 49→  // ── App Lifecycle ──────────────────────────────────────────────────────
 50→  /** Fired once per boot after consent check passes. */
 51→  app_launched: { version: string };
 52→
 53→  // ── Onboarding ─────────────────────────────────────────────────────────
 54→  onboarding_started: Record<string, never>;
 55→  onboarding_step_viewed: { step: number; step_name: string };
 56→  onboarding_completed: { duration_ms: number };
 57→
 58→  // ── Repository ─────────────────────────────────────────────────────────
 59→  /** repo_name derived from path — useful for filtering demo repo usage. */
 60→  repo_added: { repo_name?: string };
 61→  /** TODO: wire when repo removal UI is implemented. */
 62→  repo_removed: { repo_id: string; repo_name?: string };
 63→
 64→  // ── Workspace ──────────────────────────────────────────────────────────
 65→  workspace_created: { repository_id: string };
 66→  workspace_archived: WithWorkspace;
 67→  workspace_unarchived: WithWorkspace;
 68→  workspace_status_changed: WithWorkspace & { status: string };
 69→  /** Workspace init pipeline finished (initializing → ready or → error).
 70→   *  duration_ms is approximate — includes polling latency (~2s window). */
 71→  workspace_setup_completed: WithWorkspace & {
 72→    setup_status: "completed" | "failed";
 73→    duration_ms?: number;
 74→  };
 75→
 76→  // ── Session (AI Chat) ──────────────────────────────────────────────────
 77→  session_created: WithWorkspace & {
 78→    agent_type?: string;
 79→    model?: string;
 80→  };
 81→  session_message_sent: WithSession & {
 82→    has_images: boolean;
 83→    model?: string;
 84→    agent_type?: string;
 85→    /** How many messages existed in this session before this one. */
 86→    message_count?: number;
 87→    /** 0–100: how full the context window is. Signals "about to compact". */
 88→    context_used_percent?: number;
 89→  };
 90→  session_stopped: WithSession & { agent_type?: string };
 91→  /** Agent finished a turn (working → idle transition).
 92→   *  Detected via session status change in useGlobalSessionNotifications. */
 93→  ai_turn_completed: WithSession & {
 94→    agent_type?: string;
 95→    model?: string;
 96→    context_used_percent?: number;
 97→  };
 98→  /** Session entered error state. Category from agent-server error classification. */
 99→  session_error_displayed: WithSession & {
100→    error_category?: string;
101→  };
102→
103→  // ── Git / PR ───────────────────────────────────────────────────────────
104→  /** User initiated PR creation (via chat prompt or header action). */
105→  pr_create_requested: WithWorkspace & { target_branch: string };
