 1→/**
 2→ * Syncs PostHog opt-in/out state with the analytics_enabled setting.
 3→ *
 4→ * Consent model: OPT-OUT. Default is true (tracking enabled unless user disables).
 5→ * Mount once in AppContent — runs whenever the setting changes.
 6→ */
 7→import { useEffect, useRef } from "react";
 8→import { useSettings } from "@/features/settings";
 9→import { setAnalyticsEnabled, identifyUser, track } from "./track";
10→import { capabilities } from "@/platform/capabilities";
11→
12→export function useAnalyticsConsent(): void {
13→  const { data: settings } = useSettings();
14→  const prevEnabled = useRef<boolean | null>(null);
15→  const appLaunchTracked = useRef(false);
16→
17→  useEffect(() => {
18→    const enabled = settings?.analytics_enabled !== false;
19→
20→    // Skip if unchanged
21→    if (prevEnabled.current === enabled) return;
22→    prevEnabled.current = enabled;
23→
24→    setAnalyticsEnabled(enabled);
25→
26→    if (enabled) {
27→      identifyUser({
28→        theme: settings?.theme ?? "system",
29→        claude_provider: settings?.claude_provider,
30→      });
31→
32→      // Track app launch once per app lifecycle (guard prevents re-fire
33→      // if user toggles analytics off then back on)
34→      if (!appLaunchTracked.current && capabilities.ipcInvoke) {
35→        appLaunchTracked.current = true;
36→        // In Electron, get version via the preload bridge
37→        window
38→          .electronAPI!.getAppVersion()
39→          .then((version) => track("app_launched", { version }))
40→          .catch(() => track("app_launched", { version: "unknown" }));
41→      }
42→    }
43→  }, [settings?.analytics_enabled, settings?.theme, settings?.claude_provider]);
44→}
