 33→// Backfill git_origin_url for repos added before we tracked origin URLs.
 34→// Runs once at startup (fire-and-forget) so WS subscribers get the data
 35→// on their first snapshot instead of waiting for GET /repos.
 36→async function backfillGitOriginUrls(): Promise<void> {
 37→  const { execFile } = await import("child_process");
 38→  const { promisify } = await import("util");
 39→  const execFileAsync = promisify(execFile);
 40→
 41→  try {
 42→    const nullUrlRepos = db
 43→      .prepare("SELECT id, root_path FROM repositories WHERE git_origin_url IS NULL")
 44→      .all() as { id: string; root_path: string }[];
 45→    if (nullUrlRepos.length === 0) return;
 46→
 47→    let updated = 0;
 48→    // Process in batches of 5 to cap concurrent git subprocesses
 49→    const BATCH_SIZE = 5;
 50→    for (let i = 0; i < nullUrlRepos.length; i += BATCH_SIZE) {
 51→      const batch = nullUrlRepos.slice(i, i + BATCH_SIZE);
 52→      const results = await Promise.allSettled(
 53→        batch.map(async (repo) => {
 54→          const { stdout } = await execFileAsync("git", ["remote", "get-url", "origin"], {
 55→            cwd: repo.root_path,
 56→            encoding: "utf-8",
 57→            timeout: 2000,
 58→          });
 59→          const url = stdout.trim();
 60→          if (url) {
 61→            db.prepare("UPDATE repositories SET git_origin_url = ? WHERE id = ?").run(url, repo.id);
 62→            return true;
 63→          }
 64→          return false;
 65→        })
 66→      );
 67→      updated += results.filter((r) => r.status === "fulfilled" && r.value).length;
 68→    }
 69→
 70→    // Push fresh data to WS subscribers so sidebar shows GitHub icons immediately
 71→    if (updated > 0) {
 72→      invalidate(["workspaces"]);
 73→    }
 74→  } catch {
 75→    // Backfill failed — not critical, icons will appear after next workspace creation
 76→  }
 77→}
 78→void backfillGitOriginUrls();
