152→/** Spawn the agent-server bundle as a child process and connect to its WebSocket. */
153→async function spawnAgentServerAndConnect(bundlePath: string): Promise<void> {
154→  const { spawn } = await import("child_process");
155→  const fs = await import("fs");
156→
157→  if (!fs.existsSync(bundlePath)) {
158→    console.error(`[server] Agent-server bundle not found: ${bundlePath}`);
159→    return;
160→  }
161→
162→  agentServerChild = spawn(process.execPath, [bundlePath], {
163→    stdio: ["ignore", "pipe", "pipe"],
164→    env: {
165→      ...process.env,
166→      // Forward database path so agent-server can pass it to agents
167→      DATABASE_PATH: process.env.DATABASE_PATH,
168→      // Forward notebook server path
169→      NOTEBOOK_SERVER_BUNDLE_PATH: process.env.NOTEBOOK_SERVER_BUNDLE_PATH,
170→    },
171→  });
172→
173→  const agentServer = agentServerChild!;
174→  let stdoutBuffer = "";
175→
176→  agentServer.stdout?.on("data", (data: Buffer) => {
177→    stdoutBuffer += data.toString();
178→    const lines = stdoutBuffer.split("\n");
179→    stdoutBuffer = lines.pop() ?? "";
180→
181→    for (const line of lines) {
182→      const trimmed = line.trim();
183→      if (!trimmed) continue;
184→      console.log("[agent-server]", trimmed);
185→
186→      // Capture the LISTEN_URL and connect
187→      if (trimmed.startsWith("LISTEN_URL=")) {
188→        const url = trimmed.slice("LISTEN_URL=".length);
189→        console.log(`[server] Agent-server spawned and listening at ${url}`);
190→        agentService.init(url);
191→      }
192→    }
193→  });
194→
195→  agentServer.stderr?.on("data", (data: Buffer) => {
196→    for (const line of data.toString().split("\n")) {
197→      if (line.trim()) console.error("[agent-server:stderr]", line.trim());
198→    }
199→  });
200→
201→  agentServer.on("exit", (code, signal) => {
202→    console.log(`[agent-server] Exited with code=${code} signal=${signal}`);
203→    agentServerChild = null;
204→  });
205→}
