 41→// ============================================================================
 42→// Logging
 43→// ============================================================================
 44→
 45→export const logFilePath = `/tmp/deus-${process.pid}.log`;
 46→const originalLog = console.log;
 47→
 48→const LOG_LEVEL = (process.env.LOG_LEVEL || "info") as "debug" | "info" | "error";
 49→const LOG_LEVELS = { debug: 0, info: 1, error: 2 };
 50→
 51→function shouldLog(level: "debug" | "info" | "error"): boolean {
 52→  return LOG_LEVELS[level] >= LOG_LEVELS[LOG_LEVEL];
 53→}
 54→
 55→function formatLogArgs(args: any[]): string {
 56→  return args
 57→    .map((arg) => {
 58→      if (typeof arg === "string") return arg;
 59→      if (arg instanceof Error) return `${arg.message}\n${arg.stack || ""}`;
 60→      return util.inspect(arg, { depth: 4, breakLength: Infinity });
 61→    })
 62→    .join(" ");
 63→}
 64→
 65→// Buffered log writer -- avoids synchronous appendFileSync on every log call
 66→let logBuffer = "";
 67→let flushTimer: NodeJS.Timeout | null = null;
 68→
 69→function flushLogs(): void {
 70→  if (logBuffer) {
 71→    fs.appendFileSync(logFilePath, logBuffer);
 72→    logBuffer = "";
 73→  }
 74→  flushTimer = null;
 75→}
 76→
 77→function writeLog(line: string): void {
 78→  logBuffer += line;
 79→  if (!flushTimer) {
 80→    flushTimer = setTimeout(flushLogs, 100);
 81→  }
 82→  if (logBuffer.length > 8192) {
 83→    flushLogs();
 84→  }
 85→}
 86→
 87→// Ensure logs are flushed on shutdown
 88→process.on("exit", flushLogs);
 89→
 90→console.log = (...args: any[]) => {
 91→  if (!shouldLog("info")) return;
 92→  const timestamp = new Date().toISOString();
 93→  writeLog(`[${timestamp}] ${formatLogArgs(args)}\n`);
 94→};
 95→
 96→console.error = (...args: any[]) => {
 97→  const timestamp = new Date().toISOString();
 98→  const formatted = formatLogArgs(args);
 99→  writeLog(`[${timestamp}] ERROR: ${formatted}\n`);
100→  // Also write to real stderr so the backend child-process handler can
101→  // capture and forward these lines to the Electron terminal.
102→  // Without this, console.error() from bundled libraries (e.g. screen-studio)
103→  // only lands in the log file and is invisible in the dev console.
104→  process.stderr.write(`${formatted}\n`);
105→};
106→
107→console.debug = (...args: any[]) => {
108→  if (!shouldLog("debug")) return;
109→  const timestamp = new Date().toISOString();
110→  writeLog(`[${timestamp}] DEBUG: ${formatLogArgs(args)}\n`);
111→};
