117→class AgentServer {
118→  private initializedAgents = new Set<string>();
119→  private httpServer: ReturnType<typeof createHttpServer> | null = null;
120→  private wss: WebSocketServer | null = null;
121→
122→  constructor() {
123→    console.log("AgentServer: Initializing...");
124→
125→    // Graceful shutdown handlers — drain in-flight turns before exiting
126→    const gracefulShutdown = async (signal: string) => {
127→      console.log(`\n[SIGNAL] Received ${signal}, shutting down gracefully...`);
128→
129→      // 1. Stop accepting new turn/start requests
130→      setShuttingDown(true);
131→
132→      // 2. Stop accepting new WS connections (close the HTTP listener)
133→      if (this.httpServer) {
134→        this.httpServer.close();
135→        console.log("[SHUTDOWN] HTTP server closed to new connections");
136→      }
137→
138→      // 3. Wait for in-flight turns to drain (default 30s timeout)
139→      console.log("[SHUTDOWN] Waiting for in-flight turns to drain...");
140→      const drained = await waitForDrain();
141→      if (drained) {
142→        console.log("[SHUTDOWN] All turns drained successfully");
143→      } else {
144→        console.log("[SHUTDOWN] Drain timeout reached, cancelling remaining sessions");
145→        await cancelRemainingSessions();
146→      }
147→
148→      // 4. Full cleanup (kill child processes, close WS clients)
149→      try {
150→        await this.cleanup();
151→        console.log("[SIGNAL] Cleanup complete, exiting process");
152→      } catch (error) {
153→        console.error("[SIGNAL] Cleanup failed:", error);
154→      } finally {
155→        process.exit(0);
156→      }
157→    };
158→    process.on("SIGINT", () => gracefulShutdown("SIGINT"));
159→    process.on("SIGTERM", () => gracefulShutdown("SIGTERM"));
160→  }
161→
162→  /**
163→   * Wires up all JSON-RPC methods and notifications on a new connection.
164→   */
165→  private setupJsonRpc(rpcTunnel: RpcConnection): void {
166→    EventBroadcaster.attachTunnel(rpcTunnel);
167→
168→    // --- Initialize handshake (backend agent-client sends this) ---
169→    rpcTunnel.addMethod("initialize", () => {
170→      const agents = [];
171→      for (const [agentType, handler] of [
172→        ["claude", getAgent("claude")],
173→        ["codex", getAgent("codex")],
174→      ] as const) {
175→        if (handler && this.initializedAgents.has(agentType)) {
176→          agents.push({
177→            type: agentType,
178→            capabilities: handler.capabilities,
179→            initialized: true,
180→          });
181→        }
182→      }
183→      return { version: "1.0", agents };
184→    });
185→
186→    // --- Initialized notification (backend confirms handshake) ---
187→    rpcTunnel.addMethod("initialized", () => {
188→      console.log("[RPC] Backend handshake complete (initialized)");
189→      return undefined;
190→    });
191→
192→    // --- turn/start (new wire protocol method, maps to query dispatch) ---
193→    rpcTunnel.addMethod("turn/start", async (params: any) => {
194→      const sessionId = params?.sessionId;
195→      const agentType = params?.agentType || "claude";
196→      const prompt = params?.prompt;
197→      const options = params?.options || {};
198→
199→      // Reject new turns during shutdown
200→      if (isShuttingDown()) {
201→        return { accepted: false, reason: "shutting down" };
202→      }
203→
204→      if (!sessionId || !prompt) {
205→        return { accepted: false, reason: "turn/start requires sessionId and prompt" };
206→      }
207→
208→      const agent = getAgent(agentType);
209→      if (!agent) {
210→        return { accepted: false, reason: `No agent registered for type: ${agentType}` };
211→      }
212→
213→      // Track this session for graceful shutdown draining
214→      trackSession(sessionId, agentType);
215→
216→      agent
217→        .query(sessionId, prompt, options)
218→        .catch((err) => {
219→          console.error(`[turn/start] Unhandled error in ${agentType} query:`, err);
220→          const classified = classifyError(err);
221→          EventBroadcaster.sendError({
222→            id: sessionId,
223→            type: "error",
224→            error: classified.message,
225→            agentType,
226→            category: classified.category,
227→          });
228→          EventBroadcaster.emitSessionError(
229→            sessionId,
230→            agentType,
231→            classified.message,
232→            classified.category
233→          );
234→        })
235→        .finally(() => {
236→          // Untrack when the turn completes (success, error, or cancel)
237→          untrackSession(sessionId);
238→        });
239→
240→      EventBroadcaster.emitSessionStarted(sessionId, agentType);
241→
242→      console.log(`[TIMING][turn/start] DISPATCHED session=${sessionId}`);
243→      return { accepted: true };
244→    });
245→
246→    // --- turn/respond (tool relay response from backend) ---
247→    // Currently a stub: the agent-server tools use direct JSON-RPC requests
248→    // (EventBroadcaster.requestBrowserXxx) rather than the canonical
249→    // tool.request notification path. When tools migrate to the canonical
250→    // path, this handler will resolve pending promises by requestId.
251→    rpcTunnel.addMethod("turn/respond", (params: any) => {
252→      const { requestId } = params ?? {};
253→      console.log(`[AgentServer] turn/respond received (requestId=${requestId})`);
254→    });
255→
256→    // --- turn/cancel (new wire protocol method, maps to cancel dispatch) ---
257→    rpcTunnel.addMethod("turn/cancel", async (params: any) => {
258→      const sessionId = params?.sessionId;
259→      if (!sessionId) return;
260→
261→      // Try all registered agents — the backend may not send agentType for cancel
262→      for (const agentType of ["claude", "codex"] as const) {
263→        const agent = getAgent(agentType);
264→        if (agent) void agent.cancel(sessionId);
265→      }
266→    });
267→
268→    // --- session/reset (new wire protocol method) ---
269→    rpcTunnel.addMethod("session/reset", (params: any) => {
270→      const sessionId = params?.sessionId;
271→      if (!sessionId) return;
272→
273→      for (const agentType of ["claude", "codex"] as const) {
274→        const agent = getAgent(agentType);
275→        if (agent) agent.reset(sessionId);
276→      }
277→    });
278→
279→    // --- session/stop (stop a running session) ---
280→    rpcTunnel.addMethod("session/stop", async (params: any) => {
281→      const sessionId = params?.sessionId;
282→      if (!sessionId) return;
283→
284→      for (const agentType of ["claude", "codex"] as const) {
285→        const agent = getAgent(agentType);
286→        if (agent) void agent.cancel(sessionId);
287→      }
288→    });
289→
290→    // --- provider/auth (check agent authentication) ---
291→    rpcTunnel.addMethod("provider/auth", async (params: any) => {
292→      const agentType = params?.agentType || "claude";
293→      const agent = getAgent(agentType);
294→      if (!agent?.auth) throw new Error(`Agent "${agentType}" does not support auth`);
295→      return agent.auth({ cwd: params?.cwd });
296→    });
297→
298→    // --- provider/initWorkspace (slash commands, MCP servers) ---
299→    rpcTunnel.addMethod("provider/initWorkspace", async (params: any) => {
300→      const agentType = params?.agentType || "claude";
301→      const agent = getAgent(agentType);
302→      if (!agent?.initWorkspace)
303→        throw new Error(`Agent "${agentType}" does not support workspace init`);
304→      return agent.initWorkspace({
305→        cwd: params?.cwd,
306→        ghToken: params?.ghToken,
307→        providerEnvVars: params?.providerEnvVars,
308→      });
309→    });
310→
311→    // --- provider/contextUsage (token usage stats) ---
312→    rpcTunnel.addMethod("provider/contextUsage", async (params: any) => {
313→      const agentType = params?.agentType || "claude";
314→      const agent = getAgent(agentType);
315→      if (!agent?.getContextUsage)
316→        throw new Error(`Agent "${agentType}" does not support context usage`);
317→      return agent.getContextUsage({
318→        options: {
319→          cwd: params?.cwd ?? "",
320→          agentSessionId: params?.agentSessionId ?? "",
321→        },
322→      });
323→    });
324→
325→    // --- provider/updateMode (runtime permission mode change) ---
326→    rpcTunnel.addMethod("provider/updateMode", (params: any) => {
327→      const agentType = params?.agentType || "claude";
328→      const agent = getAgent(agentType);
329→      if (agent?.updatePermissionMode) {
330→        void agent.updatePermissionMode(params?.sessionId, params?.permissionMode);
331→      }
332→    });
333→
334→    // --- agent/list (introspection: list available agents) ---
335→    rpcTunnel.addMethod("agent/list", () => {
336→      const agents = [];
337→      for (const [agentType, handler] of [
338→        ["claude", getAgent("claude")],
339→        ["codex", getAgent("codex")],
340→      ] as const) {
341→        if (handler && this.initializedAgents.has(agentType)) {
342→          agents.push({ type: agentType, capabilities: handler.capabilities });
343→        }
344→      }
345→      return { agents };
346→    });
347→  }
348→
349→  /**
350→   * Handles a new WebSocket connection.
351→   * Each WS text frame is a complete JSON-RPC message (no line splitting needed).
352→   */
353→  private handleWsConnection(ws: WebSocket): void {
354→    console.log("Client connected (ws)");
355→    const transport = wsTransport(ws);
356→    const rpcTunnel = new RpcConnection(transport);
357→    this.setupJsonRpc(rpcTunnel);
358→
359→    ws.on("message", (data: Buffer | string) => {
360→      const message = typeof data === "string" ? data : data.toString("utf8");
361→      console.debug("Received WS message with length", message.length);
362→      rpcTunnel.handleMessage(message);
363→    });
364→
365→    ws.on("error", (error: Error) => {
366→      console.error("WebSocket error:", error);
367→    });
368→
369→    ws.on("close", (code: number, reason: Buffer) => {
370→      console.log(`Client disconnected (ws), code=${code} reason=${reason.toString()}`);
371→      rpcTunnel.stop();
372→      EventBroadcaster.detachTunnel(rpcTunnel);
373→    });
374→  }
375→
376→  // ==========================================================================
377→  // Lifecycle
378→  // ==========================================================================
379→
380→  /**
381→   * Kills any remaining Claude child processes spawned by this agent-server.
382→   */
383→  private async killRemainingChildProcesses(): Promise<void> {
384→    return new Promise((resolve) => {
385→      const command = `/usr/bin/pgrep -P ${process.pid}`;
386→      exec(command, (error, stdout) => {
387→        if (error) {
388→          console.log("[CLEANUP] No child processes found");
389→          resolve();
390→          return;
391→        }
392→        const childPids = stdout
393→          .trim()
394→          .split("\n")
395→          .filter((pid) => pid);
396→        if (childPids.length === 0) {
397→          console.log("[CLEANUP] No child processes to kill");
398→          resolve();
399→          return;
400→        }
401→        console.log(`[CLEANUP] Found ${childPids.length} child processes: ${childPids.join(", ")}`);
402→        childPids.forEach((pid) => {
403→          try {
404→            process.kill(Number(pid), "SIGTERM");
405→            console.log(`[CLEANUP] Sent SIGTERM to child PID ${pid}`);
406→          } catch (e) {
407→            const errorMsg = getErrorMessage(e);
408→            console.log(`[CLEANUP] Failed to kill child PID ${pid}: ${errorMsg}`);
409→          }
410→        });
411→        resolve();
412→      });
413→    });
414→  }
415→
416→  private async cleanup(): Promise<void> {
417→    await this.killRemainingChildProcesses();
418→
419→    if (this.wss) {
420→      for (const client of this.wss.clients) {
421→        client.close(1001, "Server shutting down");
422→      }
423→      this.wss.close();
424→    }
425→    if (this.httpServer) {
426→      this.httpServer.close();
427→    }
428→  }
429→
430→  /**
431→   * Starts the agent-server:
432→   * 1. Clean up stale resources
433→   * 2. Initialize agent handlers
434→   * 3. Listen on the selected transport
435→   * 4. Print connection info to stdout (consumed by the Electron main process)
436→   */
437→  async start(): Promise<void> {
438→    await this.cleanup();
439→
440→    // Register all agent handlers
441→    registerAgent(new ClaudeAgentHandler());
442→    registerAgent(new CodexAgentHandler());
443→
444→    // Initialize all registered agents
445→    console.log("Initializing agent handlers...");
446→    this.initializedAgents.clear();
447→    const initResults = initializeAllAgents();
448→    for (const [agentType, result] of initResults) {
449→      if (!result.success) {
450→        console.error(`${agentType} initialization failed:`, result.error);
451→      } else {
452→        console.log(`${agentType} handler initialized successfully`);
453→        this.initializedAgents.add(agentType);
454→      }
455→    }
456→
457→    // Mark agents as initialized for the /readyz endpoint only if at least one succeeded
458→    setAgentsInitialized(this.initializedAgents.size > 0);
459→
460→    return this.listen();
461→  }
462→
463→  private listen(): Promise<void> {
464→    return new Promise((resolve, reject) => {
465→      // Create an HTTP server for health endpoints + WS upgrade.
466→      // Binding to 127.0.0.1 — agent-server only accepts local connections.
467→      this.httpServer = createHttpServer((req, res) => {
468→        handleHttpRequest(req, res, this.wss);
469→      });
470→
471→      this.wss = new WebSocketServer({ server: this.httpServer });
472→
473→      this.wss.on("connection", (ws) => {
474→        console.log("Server: New WebSocket connection accepted");
475→        this.handleWsConnection(ws);
476→      });
477→
478→      this.wss.on("error", (error: Error) => {
479→        console.error("WebSocketServer error:", error);
480→      });
481→
482→      // Port 0 = OS-assigned dynamic port
483→      this.httpServer.listen(0, "127.0.0.1", () => {
484→        const addr = this.httpServer!.address();
485→        const port = typeof addr === "object" && addr ? addr.port : 0;
486→
487→        console.log(`Agent-server listening on ws://127.0.0.1:${port}`);
488→        console.log(`Agent-server PID: ${process.pid}`);
489→
490→        // Machine-readable output for the Electron main process / dev.sh
491→        originalLog(`LISTEN_URL=ws://127.0.0.1:${port}`);
492→        resolve();
493→      });
494→
495→      this.httpServer.on("error", (error: Error) => {
496→        console.error("HTTP server error:", error);
497→        reject(error);
498→      });
499→    });
500→  }
501→}
502→
503→// ============================================================================
504→// Global error handlers
505→// ============================================================================
506→
507→process.on("uncaughtException", (error: any) => {
508→  console.error("Uncaught Exception:", error.message);
509→  if (error.stack) console.error("Stack:", error.stack);
510→  Sentry.captureException(error);
511→  Sentry.close(2000).finally(() => process.exit(1));
512→});
513→
514→process.on("unhandledRejection", (reason, _promise) => {
515→  // Sentry's built-in onUnhandledRejectionIntegration captures and normalizes
516→  // rejection reasons automatically. We only log here for local visibility.
517→  if (reason instanceof Error) {
518→    console.error("Unhandled Rejection:", reason.message);
519→    if (reason.stack) console.error("Stack:", reason.stack);
520→  }
521→  console.error("Unhandled Rejection Reason:", JSON.stringify(reason, null, 2));
522→});
523→
524→// ============================================================================
525→// Bootstrap
526→// ============================================================================
527→
528→const server = new AgentServer();
529→server.start().catch((error) => {
530→  console.error("Startup failed:", error);
531→  process.exit(1);
532→});
