 23→export function OpenInDropdown({ workspacePath, iconOnly = false }: OpenInDropdownProps) {
 24→  const [installedApps, setInstalledApps] = useState<InstalledApp[]>([]);
 25→  const [loading, setLoading] = useState(true);
 26→  const [open, setOpen] = useState(false);
 27→  const [lastAppId, setLastAppId] = useLastOpenInApp();
 28→  const closeTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
 29→  const isHoveringRef = useRef(false);
 30→
 31→  useEffect(() => {
 32→    async function loadInstalledApps() {
 33→      try {
 34→        const apps = await native.apps.getInstalled();
 35→        setInstalledApps(apps);
 36→      } catch {
 37→        // May fail if the IPC handler isn't registered
 38→      } finally {
 39→        setLoading(false);
 40→      }
 41→    }
 42→
 43→    loadInstalledApps();
 44→  }, []);
 45→
 46→  useEffect(() => {
 47→    return () => {
 48→      if (closeTimeoutRef.current) {
 49→        clearTimeout(closeTimeoutRef.current);
 50→      }
 51→    };
 52→  }, []);
 53→
 54→  const lastApp = lastAppId ? (installedApps.find((a) => a.id === lastAppId) ?? null) : null;
 55→
 56→  function handleOpenInApp(appId: string) {
 57→    setOpen(false);
 58→    setLastAppId(appId);
 59→    track("open_in_app", { app_id: appId });
 60→    native.apps.openIn(appId, workspacePath).catch((error) => {
 61→      console.error(`Failed to open in ${appId}:`, error);
 62→    });
 63→  }
 64→
 65→  function handleQuickOpen() {
 66→    if (lastApp) {
 67→      handleOpenInApp(lastApp.id);
 68→    } else {
 69→      setOpen(true);
 70→    }
 71→  }
 72→
 73→  function handleOpen() {
 74→    if (closeTimeoutRef.current) {
 75→      clearTimeout(closeTimeoutRef.current);
 76→    }
 77→    isHoveringRef.current = true;
 78→    setOpen(true);
 79→  }
 80→
 81→  function handleClose() {
 82→    isHoveringRef.current = false;
 83→    // Very short delay to handle rapid mouse movements
 84→    closeTimeoutRef.current = setTimeout(() => {
 85→      if (!isHoveringRef.current) {
 86→        setOpen(false);
 87→      }
 88→    }, 50);
 89→  }
 90→
 91→  if (loading || installedApps.length === 0) {
 92→    return null;
 93→  }
 94→
 95→  const groups = groupAppsByCategory(installedApps);
 96→
 97→  const menuContent = (
 98→    <DropdownMenuContent
 99→      align="end"
100→      sideOffset={2}
101→      className="min-w-[140px] shadow-sm"
102→      onPointerEnter={handleOpen}
103→      onPointerLeave={handleClose}
104→    >
105→      {groups.map((group, groupIdx) => (
106→        <div key={group.category}>
107→          {groupIdx > 0 && <DropdownMenuSeparator />}
108→          {group.apps.map((app) => (
109→            <DropdownMenuItem
110→              key={app.id}
111→              onClick={() => handleOpenInApp(app.id)}
112→              className="cursor-pointer gap-2 py-1 text-xs"
113→            >
114→              {app.icon ? (
115→                <img
116→                  src={app.icon}
117→                  alt=""
118→                  className="h-5 w-5 flex-shrink-0 rounded-xs"
119→                  draggable={false}
120→                />
121→              ) : (
122→                <AppIcon appId={app.id} className="h-5 w-5 flex-shrink-0" />
123→              )}
124→              <span className={lastApp?.id === app.id ? "font-medium" : ""}>{app.name}</span>
125→              {lastApp?.id === app.id && (
126→                <Check className="text-muted-foreground ml-auto h-3 w-3" />
127→              )}
128→            </DropdownMenuItem>
129→          ))}
130→        </div>
131→      ))}
132→    </DropdownMenuContent>
133→  );
134→
135→  if (iconOnly) {
136→    return (
137→      <DropdownMenu open={open} onOpenChange={setOpen} modal={false}>
138→        <Tooltip delayDuration={200}>
139→          <DropdownMenuTrigger asChild>
140→            <TooltipTrigger asChild>
141→              <Button
142→                aria-label={lastApp ? `Open in ${lastApp.name}` : "Open in app"}
143→                variant="ghost"
144→                size="icon"
145→                className="text-muted-foreground/80 hover:text-foreground hover:bg-muted/10 h-9 w-9 rounded-lg transition-colors duration-200 ease-out"
146→              >
147→                {lastApp?.icon ? (
148→                  <img src={lastApp.icon} alt="" className="h-4 w-4 rounded-xs" draggable={false} />
149→                ) : (
150→                  <ArrowUpRight className="h-4 w-4" />
151→                )}
152→              </Button>
153→            </TooltipTrigger>
154→          </DropdownMenuTrigger>
155→          <TooltipContent side="bottom">
156→            <p className="text-xs">
157→              {lastApp ? `Open in ${lastApp.name}` : "Open in\u2026"}
158→              <span className="text-muted-foreground ml-2">⌘O</span>
159→            </p>
160→          </TooltipContent>
161→        </Tooltip>
162→        {menuContent}
163→      </DropdownMenu>
164→    );
165→  }
166→
167→  return (
168→    <DropdownMenu open={open} onOpenChange={setOpen} modal={false}>
169→      <div className="border-border flex h-8 items-center rounded-lg border">
170→        <Tooltip delayDuration={200}>
171→          <TooltipTrigger asChild>
172→            <button
173→              type="button"
174→              onClick={handleQuickOpen}
175→              className="text-muted-foreground/80 hover:text-foreground hover:bg-muted/10 flex h-full items-center gap-2 rounded-l-lg px-3 transition-colors duration-200"
176→            >
177→              {lastApp?.icon ? (
178→                <img src={lastApp.icon} alt="" className="h-4 w-4 rounded-xs" draggable={false} />
179→              ) : (
180→                <ArrowUpRight className="h-4 w-4" />
181→              )}
182→              <span className="text-sm">Open</span>
183→            </button>
184→          </TooltipTrigger>
185→          <TooltipContent side="bottom">
186→            <p className="text-xs">
187→              {lastApp ? `Open in ${lastApp.name}` : "Open in\u2026"}
188→              <span className="text-muted-foreground ml-2">⌘O</span>
189→            </p>
190→          </TooltipContent>
191→        </Tooltip>
192→
193→        <div className="bg-border h-4 w-px" />
194→
195→        <DropdownMenuTrigger asChild>
196→          <button
197→            type="button"
198→            aria-label="Choose app to open in"
199→            className="text-muted-foreground hover:text-foreground hover:bg-muted/10 flex h-full items-center rounded-r-lg px-1.5 transition-colors duration-200"
200→            onPointerEnter={handleOpen}
201→            onPointerLeave={handleClose}
202→          >
203→            <ChevronRight
204→              className={`h-3.5 w-3.5 transition-transform duration-200 ease-out ${
205→                open ? "rotate-90" : ""
206→              }`}
207→            />
208→          </button>
209→        </DropdownMenuTrigger>
