234→// ---------------------------------------------------------------------------
235→// HeaderOpenButton — split button: quick open (last-used) + dropdown
236→// ---------------------------------------------------------------------------
237→
238→function HeaderOpenButton({ workspacePath }: { workspacePath: string }) {
239→  const [apps, setApps] = useState<InstalledApp[]>([]);
240→  const [loading, setLoading] = useState(true);
241→  const [open, setOpen] = useState(false);
242→  const [copied, setCopied] = useState(false);
243→  const [lastAppId, setLastAppId] = useLastOpenInApp();
244→  const closeTimeoutRef = useRef<ReturnType<typeof setTimeout>>();
245→  const isHoveringRef = useRef(false);
246→
247→  useEffect(() => {
248→    native.apps
249→      .getInstalled()
250→      .then(setApps)
251→      .catch(() => {})
252→      .finally(() => setLoading(false));
253→  }, []);
254→
255→  // Default app: last-used, or first editor in the list
256→  const lastApp = lastAppId ? (apps.find((a) => a.id === lastAppId) ?? null) : null;
257→  const defaultApp = lastApp ?? apps[0] ?? null;
258→
259→  function handleOpenInApp(appId: string) {
260→    setOpen(false);
261→    setLastAppId(appId);
262→    track("open_in_app", { app_id: appId });
263→    native.apps.openIn(appId, workspacePath).catch(() => {});
264→  }
265→
266→  function handleQuickOpen() {
267→    if (loading) return;
268→    if (defaultApp) {
269→      handleOpenInApp(defaultApp.id);
270→    } else {
271→      setOpen(true);
272→    }
273→  }
274→
275→  function handleCopyPath() {
276→    navigator.clipboard
277→      .writeText(workspacePath)
278→      .then(() => {
279→        setCopied(true);
280→        setTimeout(() => setCopied(false), 2000);
281→      })
282→      .catch(() => {});
283→    setOpen(false);
284→  }
285→
286→  function handleOpen() {
287→    if (closeTimeoutRef.current) clearTimeout(closeTimeoutRef.current);
288→    isHoveringRef.current = true;
289→    setOpen(true);
290→  }
291→
292→  function handleClose() {
293→    isHoveringRef.current = false;
294→    closeTimeoutRef.current = setTimeout(() => {
295→      if (!isHoveringRef.current) setOpen(false);
296→    }, 50);
297→  }
298→
299→  useEffect(() => {
300→    return () => {
301→      if (closeTimeoutRef.current) clearTimeout(closeTimeoutRef.current);
302→    };
303→  }, []);
304→
305→  // Hide only after loading confirms no apps installed (web mode)
306→  if (!loading && apps.length === 0) {
307→    return null;
308→  }
309→
310→  const groups = groupAppsByCategory(apps);
311→
312→  return (
313→    <DropdownMenu open={open} onOpenChange={setOpen} modal={false}>
314→      <div className="border-border-strong flex h-7 shrink-0 items-center rounded-lg border">
315→        {/* Left: quick-open action */}
316→        <Tooltip delayDuration={200}>
317→          <TooltipTrigger asChild>
318→            <button
319→              type="button"
320→              onClick={handleQuickOpen}
321→              className="text-text-subtle hover:bg-bg-muted flex h-full shrink-0 items-center gap-1.5 rounded-l-lg px-2 transition-colors duration-200"
322→            >
323→              {defaultApp?.icon ? (
324→                <img
325→                  src={defaultApp.icon}
326→                  alt=""
327→                  className="h-4 w-4 shrink-0 rounded-xs"
328→                  draggable={false}
329→                />
330→              ) : (
331→                <ArrowUpRight className="h-[11px] w-[11px] shrink-0" />
332→              )}
333→              <span className="shrink-0 text-sm font-medium">Open</span>
334→            </button>
335→          </TooltipTrigger>
336→          <TooltipContent side="bottom">
337→            <p className="text-xs">
338→              {defaultApp ? `Open in ${defaultApp.name}` : "Open in\u2026"}
339→              <span className="text-text-muted ml-2">⌘O</span>
340→            </p>
341→          </TooltipContent>
342→        </Tooltip>
343→
344→        {/* Divider */}
345→        <div className="bg-border-strong h-4 w-px shrink-0" />
346→
347→        {/* Right: dropdown chevron */}
348→        <DropdownMenuTrigger asChild>
349→          <button
350→            type="button"
351→            aria-label="Choose app to open in"
352→            className="text-text-muted hover:bg-bg-muted hover:text-text-subtle flex h-full shrink-0 items-center rounded-r-lg px-1.5 transition-colors duration-200"
353→            onPointerEnter={handleOpen}
354→            onPointerLeave={handleClose}
355→          >
356→            <ChevronDown className="h-2.5 w-2.5" />
357→          </button>
358→        </DropdownMenuTrigger>
359→      </div>
360→
361→      <DropdownMenuContent
362→        align="end"
363→        sideOffset={4}
364→        className="min-w-[140px] shadow-sm"
365→        onPointerEnter={handleOpen}
366→        onPointerLeave={handleClose}
367→      >
368→        {groups.map((group, groupIdx) => (
369→          <div key={group.category}>
370→            {groupIdx > 0 && <DropdownMenuSeparator />}
371→            {group.apps.map((app) => (
372→              <DropdownMenuItem
373→                key={app.id}
374→                onClick={() => handleOpenInApp(app.id)}
375→                className="cursor-pointer gap-2 py-1 text-xs"
376→              >
377→                {app.icon ? (
378→                  <img
379→                    src={app.icon}
380→                    alt=""
381→                    className="h-5 w-5 flex-shrink-0 rounded-xs"
382→                    draggable={false}
383→                  />
384→                ) : (
385→                  <AppIcon appId={app.id} className="h-5 w-5 flex-shrink-0" />
386→                )}
387→                <span className={lastApp?.id === app.id ? "font-medium" : ""}>{app.name}</span>
388→                {lastApp?.id === app.id && <Check className="text-text-muted ml-auto h-3 w-3" />}
389→              </DropdownMenuItem>
390→            ))}
391→          </div>
392→        ))}
393→        <DropdownMenuSeparator />
394→        <DropdownMenuItem
395→          onClick={handleCopyPath}
396→          className="text-text-muted cursor-pointer gap-2 py-1 text-xs"
397→        >
398→          {copied ? (
399→            <Check className="h-3.5 w-3.5 flex-shrink-0" />
400→          ) : (
401→            <Copy className="h-3.5 w-3.5 flex-shrink-0" />
402→          )}
403→          {copied ? "Copied!" : "Copy path"}
404→        </DropdownMenuItem>
405→      </DropdownMenuContent>
406→    </DropdownMenu>
407→  );
408→}
