  1→/**
  2→ * PR Actions -- right-side actions for the content panel header.
  3→ *
  4→ * Architecture: PRStatus (bag of optionals) -> derivePRActionState (pure function)
  5→ * -> PRActionState (discriminated union) -> exhaustive match -> JSX.
  6→ *
  7→ * Each PR state maps to exactly one visual representation:
  8→ *   - "#N" link + contextual action button, OR
  9→ *   - "#N" link + status text (non-actionable), OR
 10→ *   - Create PR split button (pre-PR)
 11→ *
 12→ * No redundant chips. The button IS the status indicator.
 13→ */
 14→
 15→import { useState, useEffect } from "react";
 16→import {
 17→  GitMerge,
 18→  GitPullRequestCreate,
 19→  GitPullRequestClosed,
 20→  ChevronDown,
 21→  Archive,
 22→  AlertTriangle,
 23→  CircleX,
 24→  Loader2,
 25→  MessageSquareWarning,
 26→  FileWarning,
 27→  WifiOff,
 28→} from "lucide-react";
 29→import { match } from "ts-pattern";
 30→import { track } from "@/platform/analytics";
 31→import { Tooltip, TooltipContent, TooltipTrigger } from "@/components/ui/tooltip";
 32→import { cn } from "@/shared/lib/utils";
 33→import { BranchSelector } from "./BranchSelector";
 34→import {
 35→  RESOLVE_CONFLICTS,
 36→  fixCIPrompt,
 37→  ADDRESS_REVIEW,
 38→  MERGE_PR,
 39→} from "@/features/session/lib/sessionPrompts";
 40→import { derivePRActionState, type PRActionState } from "../lib/prState";
 41→import type { PRStatus, GhCliStatus } from "@/shared/types";
 42→
 43→// ---------------------------------------------------------------------------
 44→// Props
 45→// ---------------------------------------------------------------------------
 46→
 47→interface PRActionsProps {
 48→  prStatus: PRStatus | null;
 49→  ghStatus?: GhCliStatus | null;
 50→  onCreatePR?: () => void;
 51→  onSendAgentMessage?: (text: string) => void;
 52→  onArchive?: () => void;
 53→  targetBranch: string;
 54→  onTargetBranchChange: (branch: string) => void;
 55→  workspaceId?: string;
 56→  repoId?: string;
 57→}
 58→
 59→// ---------------------------------------------------------------------------
 60→// Main component
 61→// ---------------------------------------------------------------------------
 62→
 63→export function PRActions({
 64→  prStatus,
 65→  ghStatus,
 66→  onCreatePR,
 67→  onSendAgentMessage,
 68→  onArchive,
 69→  targetBranch: targetBranchProp = "main",
 70→  onTargetBranchChange,
 71→  workspaceId,
 72→  repoId,
 73→}: PRActionsProps) {
 74→  const [localTargetBranch, setLocalTargetBranch] = useState(targetBranchProp);
 75→  useEffect(() => {
 76→    setLocalTargetBranch(targetBranchProp);
 77→  }, [targetBranchProp]);
 78→
 79→  const handleBranchSelect = (name: string) => {
 80→    setLocalTargetBranch(name);
 81→    onTargetBranchChange(name);
 82→  };
 83→
 84→  const state = derivePRActionState(prStatus, ghStatus, localTargetBranch);
 85→
 86→  return (
 87→    <div className="flex items-center gap-1.5">
 88→      {/* PR number link -- shown for all states that have a PR */}
 89→      <PRLink state={state} />
 90→
 91→      {/* State-specific rendering: status text OR action button */}
 92→      {match(state)
 93→        .with({ type: "gh_unavailable" }, (s) => <GhWarning reason={s.reason} />)
 94→        .with({ type: "error" }, (s) => <ErrorWarning reason={s.reason} />)
 95→        .with({ type: "no_pr" }, () => (
 96→          <CreatePRButton
 97→            targetBranch={localTargetBranch}
 98→            repoId={repoId}
 99→            onBranchSelect={handleBranchSelect}
100→            onCreatePR={onCreatePR}
101→          />
102→        ))
103→        .with({ type: "ci_pending" }, (s) => (
104→          <StatusText
105→            icon={<Loader2 className="h-3.5 w-3.5 animate-spin" strokeWidth={1.5} />}
106→            label={s.checksTotal > 0 ? `${s.checksDone}/${s.checksTotal} checks` : "Checks running"}
107→            variant="pending"
108→          />
109→        ))
110→        .with({ type: "awaiting_review" }, () => (
111→          <StatusText label="Awaiting review" variant="review" />
112→        ))
113→        .with({ type: "closed" }, () => (
114→          <StatusText
115→            icon={<GitPullRequestClosed className="h-3 w-3" />}
116→            label="Closed"
117→            variant="closed"
118→          />
119→        ))
120→        .with({ type: "ci_failing" }, (s) => (
121→          <ActionButton
122→            icon={<CircleX className="h-2.5 w-2.5" />}
123→            label={s.checksTotal > 0 ? `Fix CI · ${s.checksDone}/${s.checksTotal}` : "Fix CI"}
124→            variant="destructive"
125→            onClick={() => onSendAgentMessage?.(fixCIPrompt(s.failingChecks))}
126→            disabled={!onSendAgentMessage}
127→          />
128→        ))
129→        .with({ type: "conflicts" }, () => (
130→          <ActionButton
131→            icon={<FileWarning className="h-2.5 w-2.5" />}
132→            label="Resolve Conflicts"
133→            variant="destructive"
134→            onClick={() => onSendAgentMessage?.(RESOLVE_CONFLICTS)}
135→            disabled={!onSendAgentMessage}
136→          />
137→        ))
138→        .with({ type: "changes_requested" }, () => (
139→          <ActionButton
140→            icon={<MessageSquareWarning className="h-2.5 w-2.5" />}
141→            label="Address Review"
142→            variant="warning"
143→            onClick={() => onSendAgentMessage?.(ADDRESS_REVIEW)}
144→            disabled={!onSendAgentMessage}
145→          />
146→        ))
147→        .with({ type: "ready_to_merge" }, (s) => (
148→          <ActionButton
149→            icon={<GitMerge className="h-2.5 w-2.5" />}
150→            label={`Merge into ${s.targetBranch}`}
151→            variant="success"
152→            onClick={() => {
153→              if (workspaceId) {
154→                track("pr_merged", { workspace_id: workspaceId, pr_number: s.prNumber });
155→              }
156→              onSendAgentMessage?.(MERGE_PR);
157→            }}
158→            disabled={!onSendAgentMessage}
159→          />
160→        ))
161→        .with({ type: "merged" }, () =>
162→          onArchive ? (
163→            <ActionButton
164→              icon={<Archive className="h-2.5 w-2.5" />}
165→              label="Archive"
166→              variant="primary"
167→              onClick={onArchive}
168→            />
169→          ) : null
170→        )
171→        .exhaustive()}
172→    </div>
173→  );
174→}
