176→// ---------------------------------------------------------------------------
177→// PRLink -- "#N" clickable link to open PR in browser
178→// ---------------------------------------------------------------------------
179→
180→function PRLink({ state }: { state: PRActionState }) {
181→  if (state.type === "gh_unavailable" || state.type === "no_pr" || state.type === "error")
