190→          rel="noopener noreferrer"
191→          className={cn(
192→            "ease flex items-center gap-1 rounded-lg px-1.5 py-1 text-sm font-semibold transition-colors duration-200",
193→            PR_LINK_COLORS[state.type] ?? "text-text-secondary hover:text-text-primary"
194→          )}
195→        >
196→          <GitPullRequestCreate className="h-3 w-3" />#{state.prNumber}
197→        </a>
198→      </TooltipTrigger>
199→      <TooltipContent side="bottom">
200→        <p className="text-xs">Open PR in browser</p>
201→      </TooltipContent>
202→    </Tooltip>
203→  );
204→}
