234→// ---------------------------------------------------------------------------
235→// ErrorWarning -- tooltip for GitHub connectivity errors
236→// ---------------------------------------------------------------------------
237→
238→function ErrorWarning({ reason }: { reason: "timeout" | "network" }) {
239→  return (
240→    <Tooltip delayDuration={200}>
241→      <TooltipTrigger asChild>
242→        <button
243→          type="button"
244→          aria-label="GitHub unreachable"
