262→// ---------------------------------------------------------------------------
263→// StatusText -- non-actionable status (CI pending, awaiting review, closed)
264→// ---------------------------------------------------------------------------
265→
266→const STATUS_VARIANT_CLASSES = {
267→  pending: "bg-warning/10 text-warning",
268→  review: "bg-primary/10 text-primary",
269→  closed: "bg-muted text-muted-foreground",
270→} as const;
271→
272→function StatusText({
273→  icon,
274→  label,
275→  variant,
276→}: {
277→  icon?: React.ReactNode;
278→  label: string;
279→  variant: keyof typeof STATUS_VARIANT_CLASSES;
280→}) {
281→  return (
282→    <span
283→      className={cn(
284→        "flex h-7 items-center gap-1.5 rounded-lg px-2.5 text-sm font-medium",
285→        STATUS_VARIANT_CLASSES[variant]
286→      )}
287→    >
288→      {icon}
289→      {label}
290→    </span>
291→  );
292→}
