294→// ---------------------------------------------------------------------------
295→// ActionButton -- colored action button for fixable / actionable states
296→// ---------------------------------------------------------------------------
297→
298→const VARIANT_CLASSES = {
299→  primary: "bg-primary text-primary-foreground",
300→  destructive: "bg-destructive text-destructive-foreground",
301→  warning: "bg-warning text-warning-foreground",
302→  success: "bg-success text-success-foreground",
303→} as const;
