  1→import { useState, useEffect } from "react";
  2→import type { FallbackProps } from "react-error-boundary";
  3→import { Button } from "@/components/ui/button";
  4→import { native } from "@/platform";
  5→import { normalizeError } from "@/shared/utils/errorReporting";
  6→
  7→/**
  8→ * Default error fallback for the app-level error boundary.
  9→ * Shows a user-friendly error message with retry option.
 10→ * Stack trace only visible in development.
 11→ *
 12→ * IMPORTANT: The main window starts hidden (show: false in createWindow).
 13→ * If an error occurs before the frontend calls show_main_window or
 14→ * enter_onboarding_mode, the error page renders inside an invisible window.
 15→ * We force-show the window here so the user can actually see the error.
 16→ */
 17→export function ErrorFallback({ error, resetErrorBoundary }: FallbackProps) {
 18→  const [copied, setCopied] = useState(false);
 19→
 20→  // Force-show the window so the error is visible to the user.
 21→  // Without this, errors during boot leave the window hidden forever.
 22→  useEffect(() => {
 23→    native.window.show().catch(console.error);
 24→  }, []);
 25→  const normalizedError = normalizeError(error);
 26→  const componentStack =
 27→    typeof window !== "undefined"
 28→      ? (window as { __APP_LAST_COMPONENT_STACK__?: string }).__APP_LAST_COMPONENT_STACK__
 29→      : undefined;
 30→
 31→  async function copyErrorDetails() {
 32→    const details = [
 33→      `Message: ${normalizedError.message}`,
 34→      componentStack ? `\nComponent stack:\n${componentStack}` : "",
 35→      normalizedError.stack ? `\nStack:\n${normalizedError.stack}` : "",
 36→    ].join("\n");
 37→
 38→    try {
 39→      if (navigator.clipboard?.writeText) {
 40→        await navigator.clipboard.writeText(details);
 41→      } else {
 42→        const textarea = document.createElement("textarea");
 43→        textarea.value = details;
 44→        textarea.setAttribute("readonly", "true");
 45→        textarea.style.position = "fixed";
 46→        textarea.style.opacity = "0";
 47→        document.body.appendChild(textarea);
 48→        textarea.select();
 49→        document.execCommand("copy");
 50→        document.body.removeChild(textarea);
 51→      }
 52→      setCopied(true);
 53→      setTimeout(() => setCopied(false), 2000);
 54→    } catch {
 55→      // Swallow copy errors; user can still read details.
 56→    }
 57→  }
 58→
 59→  return (
 60→    <div className="bg-background text-foreground flex min-h-screen items-center justify-center p-6">
 61→      <div className="bg-card/60 border-border/60 w-full max-w-2xl rounded-2xl border p-6 shadow-sm backdrop-blur">
 62→        <div className="flex items-start gap-4">
 63→          <div className="bg-destructive/10 text-destructive flex h-12 w-12 items-center justify-center rounded-full">
 64→            <span className="text-xl" aria-hidden="true">
 65→              &#x26A0;&#xFE0F;
 66→            </span>
 67→          </div>
 68→          <div className="flex-1">
 69→            <h2 className="text-xl font-semibold">Something went wrong</h2>
 70→            <p className="text-muted-foreground mt-1">
 71→              The application encountered an unexpected error. You can try again or reload.
 72→            </p>
 73→          </div>
 74→        </div>
 75→
 76→        {/* Error details - only in development */}
 77→        {Boolean(error) && (
 78→          <details className="mt-5 text-left">
 79→            <summary className="bg-muted/60 hover:bg-muted cursor-pointer rounded-lg px-3 py-2 text-sm font-medium">
 80→              Error details
 81→            </summary>
 82→            <div className="bg-muted/50 max-h-56 overflow-auto rounded-lg p-4 font-mono text-xs">
 83→              <div className="mb-3 flex items-center justify-end">
 84→                <Button size="sm" variant="outline" onClick={copyErrorDetails}>
 85→                  {copied ? "Copied" : "Copy details"}
 86→                </Button>
 87→              </div>
 88→              <strong className="text-foreground">Message:</strong>
 89→              <pre className="text-foreground/90 mt-2 whitespace-pre-wrap">
 90→                {normalizedError.message}
 91→              </pre>
 92→              {import.meta.env.DEV && normalizedError.stack && (
 93→                <>
 94→                  <strong className="text-foreground mt-4 block">Stack trace:</strong>
 95→                  <pre className="text-muted-foreground mt-2 whitespace-pre-wrap">
 96→                    {normalizedError.stack}
 97→                  </pre>
 98→                </>
 99→              )}
100→              {import.meta.env.DEV && componentStack && (
101→                <>
102→                  <strong className="text-foreground mt-4 block">Component stack:</strong>
103→                  <pre className="text-muted-foreground mt-2 whitespace-pre-wrap">
104→                    {componentStack}
105→                  </pre>
106→                </>
107→              )}
108→            </div>
109→          </details>
110→        )}
111→
112→        {/* Action buttons */}
113→        <div className="mt-6 flex flex-wrap items-center justify-end gap-3">
114→          <Button onClick={resetErrorBoundary}>Try Again</Button>
115→          <Button onClick={() => window.location.reload()} variant="outline">
116→            Reload
117→          </Button>
118→        </div>
119→      </div>
120→    </div>
121→  );
122→}
