 1→/**
 2→ * Settings Query Hooks
 3→ * TanStack Query hooks for settings management
 4→ */
 5→
 6→import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";
 7→import { produce } from "immer";
 8→import { SettingsService } from "./settings.service";
 9→import { queryKeys } from "@/shared/api/queryKeys";
10→import { track } from "@/platform/analytics";
11→import type { Settings } from "../types";
12→
13→/**
14→ * Fetch all settings
15→ */
16→export function useSettings() {
17→  return useQuery({
18→    queryKey: queryKeys.settings.all,
19→    queryFn: () => SettingsService.fetch(),
20→    staleTime: 30000, // Cache for 30s (settings change less frequently)
21→  });
22→}
23→
24→/**
25→ * Fetch agent provider auth status (Claude / Codex)
26→ */
27→export function useAgentAuth() {
28→  return useQuery({
29→    queryKey: queryKeys.settings.agentAuth,
30→    queryFn: () => SettingsService.fetchAgentAuth(),
31→    staleTime: 60000, // Cache for 60s — auth status changes infrequently
32→  });
33→}
34→
35→/**
36→ * Update settings mutation with optimistic update
37→ */
38→export function useUpdateSettings() {
39→  const queryClient = useQueryClient();
40→
41→  return useMutation({
42→    mutationFn: (settings: Partial<Settings>) => SettingsService.update(settings),
43→
44→    // Optimistic update: Apply settings immediately
45→    onMutate: async (newSettings: Partial<Settings>) => {
46→      await queryClient.cancelQueries({ queryKey: queryKeys.settings.all });
47→
48→      const previousSettings = queryClient.getQueryData<Settings>(queryKeys.settings.all);
49→
50→      queryClient.setQueryData<Settings>(queryKeys.settings.all, (old) => {
51→        if (!old) return old;
52→        return produce(old, (draft) => {
53→          Object.assign(draft, newSettings);
54→        });
55→      });
56→
57→      return { previousSettings };
58→    },
59→
60→    onError: (_err, _newSettings, context) => {
61→      if (context?.previousSettings) {
62→        queryClient.setQueryData(queryKeys.settings.all, context.previousSettings);
63→      }
64→    },
65→
66→    onSuccess: (_data, newSettings) => {
67→      // Track each changed key. Only include value for safe enum-type settings
68→      // (theme, provider). Never log API keys or free-text inputs.
69→      const SAFE_VALUE_KEYS = new Set(["theme", "claude_provider"]);
70→      for (const key of Object.keys(newSettings)) {
71→        const value = SAFE_VALUE_KEYS.has(key)
72→          ? String((newSettings as Record<string, unknown>)[key])
73→          : undefined;
74→        track("setting_changed", { key, value });
75→      }
76→    },
77→
78→    onSettled: () => {
79→      queryClient.invalidateQueries({ queryKey: queryKeys.settings.all });
80→    },
81→  });
82→}
