  1→/**
  2→ * useSessionActions Hook
  3→ *
  4→ * Centralizes all session action handlers (send, stop, compact, create PR).
  5→ * Extracted from SessionPanel to reduce component complexity.
  6→ *
  7→ * Message Flow (agent-server-owns-send):
  8→ * 1. User clicks send → useSendMessage routes through socket → agent-server
  9→ * 2. Agent-server atomically: saves user message + sets status=working + dispatches agent
 10→ * 3. Agent-server streams response → saves to DB → notifies backend
 11→ * 4. Backend pushes q:snapshot/q:delta to WS subscribers → React Query cache → UI updates
 12→ */
 13→
 14→import { useCallback } from "react";
 15→import { toast } from "sonner";
 16→import { useSendMessage, useStopSession } from "../api/session.queries";
 17→import { sendCommand, connect, isConnected } from "@/platform/ws";
 18→import { track } from "@/platform/analytics";
 19→import { type RuntimeAgentType } from "../lib/agentRuntime";
 20→import { COMPACT_CONVERSATION, createPRPrompt } from "../lib/sessionPrompts";
 21→
 22→interface UseSessionActionsProps {
 23→  sessionId: string;
 24→  workspaceId?: string;
 25→  workspacePath: string;
 26→  messageInput: string;
 27→  model?: string;
 28→  agentType?: RuntimeAgentType;
 29→  permissionMode?: string;
 30→  onMessageSent?: () => void;
 31→  targetBranch?: string;
 32→}
 33→
 34→interface UseSessionActionsReturn {
 35→  // Actions
 36→  sendMessage: (customContent?: string) => Promise<void>;
 37→  stopSession: () => Promise<void>;
 38→  compactConversation: () => Promise<void>;
 39→  createPR: () => Promise<void>;
 40→
 41→  // Status
 42→  sending: boolean;
 43→}
 44→
 45→export function useSessionActions({
 46→  sessionId,
 47→  workspaceId,
 48→  workspacePath,
 49→  messageInput,
 50→  model,
 51→  agentType = "claude",
 52→  permissionMode,
 53→  onMessageSent,
 54→  targetBranch = "main",
 55→}: UseSessionActionsProps): UseSessionActionsReturn {
 56→  const sendMessageMutation = useSendMessage();
 57→  const stopSessionMutation = useStopSession();
 58→
 59→  const sendMessage = useCallback(
 60→    async (customContent?: string) => {
 61→      const content = customContent || messageInput.trim();
 62→      if (!content || sendMessageMutation.isPending) return;
 63→
 64→      try {
 65→        // Single atomic call: agent-server saves message + starts agent.
 66→        // Optimistic UI fires in onMutate, rollback fires in onError.
 67→        await sendMessageMutation.mutateAsync({
 68→          sessionId,
 69→          content,
 70→          model,
 71→          cwd: workspacePath,
 72→          agentType,
 73→          permissionMode,
 74→        });
 75→      } catch (error) {
 76→        console.error("Failed to send message:", error);
 77→        // onError already rolled back optimistic update.
 78→        // No stopSession cleanup needed — agent-server didn't persist anything on failure.
 79→        const reason = error instanceof Error ? error.message : "Failed to send message";
 80→        toast.error(reason);
 81→        return;
 82→      }
 83→
 84→      try {
 85→        onMessageSent?.();
 86→      } catch (callbackError) {
 87→        console.error("[useSessionActions] onMessageSent callback failed:", callbackError);
 88→      }
 89→    },
 90→    [
 91→      messageInput,
 92→      model,
 93→      sendMessageMutation,
 94→      sessionId,
 95→      workspacePath,
 96→      agentType,
 97→      permissionMode,
 98→      onMessageSent,
 99→    ]
100→  );
101→
102→  const stopSession = useCallback(async () => {
103→    try {
104→      // Cancel the agent-server agent first so it stops consuming API tokens
105→      try {
106→        if (!isConnected()) await connect();
107→        await sendCommand("stopSession", { sessionId });
108→      } catch (cancelError) {
109→        console.error("[useSessionActions] Cancel query failed:", cancelError);
110→      }
111→      // Then update DB status to idle
112→      await stopSessionMutation.mutateAsync(sessionId);
113→    } catch (error) {
114→      console.error("Failed to stop session:", error);
115→    }
116→  }, [stopSessionMutation, sessionId, agentType]);
117→
118→  const compactConversation = useCallback(() => {
119→    return sendMessage(COMPACT_CONVERSATION);
120→  }, [sendMessage]);
121→
122→  const createPR = useCallback(() => {
123→    if (workspaceId) {
124→      track("pr_create_requested", { workspace_id: workspaceId, target_branch: targetBranch });
125→    }
126→    return sendMessage(createPRPrompt(targetBranch));
127→  }, [sendMessage, workspaceId, targetBranch]);
