 17→/** Full-screen onboarding view — dark, grain-textured, CLI-inspired. */
 18→export function OnboardingOverlay() {
 19→  const { refetch } = useSettings();
 20→
 21→  const [currentStep, setCurrentStep] = useState<OnboardingStep>(0);
 22→  const [animClass, setAnimClass] = useState("");
 23→  const [animating, setAnimating] = useState(false);
 24→  const [exiting, setExiting] = useState(false);
 25→  const onboardingStartRef = useRef(0);
 26→
 27→  useEffect(() => {
 28→    onboardingStartRef.current = Date.now();
 29→    native.window.enterOnboarding().catch(console.error);
 30→  }, []);
 31→
 32→  const trackedRef = useRef(false);
 33→  useEffect(() => {
 34→    if (trackedRef.current) return;
 35→    trackedRef.current = true;
 36→    track("onboarding_started");
 37→  }, []);
 38→
 39→  useEffect(() => {
 40→    if (!exiting) return;
 41→    const timer = setTimeout(() => void refetch(), 600);
 42→    return () => clearTimeout(timer);
 43→  }, [exiting, refetch]);
 44→
 45→  const goForward = useCallback(() => {
 46→    if (animating) return;
 47→    setAnimating(true);
 48→    setAnimClass(
 49→      "animate-[onboarding-step-exit-forward_160ms_cubic-bezier(.215,.61,.355,1)_forwards]"
 50→    );
 51→    setTimeout(() => {
 52→      const nextStep = Math.min(currentStep + 1, 4) as OnboardingStep;
 53→      setCurrentStep(nextStep);
 54→      track("onboarding_step_viewed", { step: nextStep, step_name: STEP_NAMES[nextStep] });
 55→      setAnimClass("animate-[onboarding-step-enter-forward_240ms_cubic-bezier(.215,.61,.355,1)]");
 56→      setAnimating(false);
 57→    }, 160);
 58→  }, [animating, currentStep]);
 59→
 60→  const goBack = useCallback(() => {
 61→    if (animating) return;
 62→    setAnimating(true);
 63→    setAnimClass(
 64→      "animate-[onboarding-step-exit-back_160ms_cubic-bezier(.215,.61,.355,1)_forwards]"
 65→    );
 66→    setTimeout(() => {
 67→      setCurrentStep((prev) => Math.max(prev - 1, 0) as OnboardingStep);
 68→      setAnimClass("animate-[onboarding-step-enter-back_240ms_cubic-bezier(.215,.61,.355,1)]");
 69→      setAnimating(false);
 70→    }, 160);
 71→  }, [animating]);
 72→
 73→  const handleComplete = useCallback(() => {
 74→    if (exiting) return;
 75→    track("onboarding_completed", { duration_ms: Date.now() - onboardingStartRef.current });
 76→    native.window.exitOnboarding().catch(console.error);
 77→    setExiting(true);
 78→  }, [exiting]);
 79→
 80→  return (
 81→    <div
 82→      className={cn(
 83→        "fixed inset-0 flex items-center justify-center",
 84→        exiting && "opacity-0 transition-opacity duration-500 ease-out"
 85→      )}
 86→      style={{ zIndex: 9999 }}
 87→    >
 88→      {/* Background: black → dark gray gradient (bottom up) */}
 89→      <div
 90→        className="absolute inset-0"
 91→        style={{
 92→          background: "linear-gradient(to top, oklch(0.14 0.005 264), oklch(0.04 0.002 264) 70%)",
 93→        }}
 94→      />
 95→
 96→      {/* Film grain overlay */}
 97→      <div className="onboarding-grain absolute inset-0 opacity-[0.035]" />
 98→
 99→      {/* Content */}
100→      <div
101→        className={cn(
102→          "relative z-10 w-full max-w-[560px] px-10",
103→          currentStep === 0 ? "h-[80vh]" : "",
104→          !exiting && "animate-[onboarding-card-enter_420ms_cubic-bezier(.215,.61,.355,1)_forwards]"
105→        )}
106→        style={{ opacity: exiting ? undefined : 0 }}
107→      >
108→        {currentStep !== 0 && (
109→          <div className="flex justify-center pb-6">
110→            <StepIndicator currentStep={currentStep} totalSteps={TOTAL_STEPS} />
111→          </div>
112→        )}
113→
114→        <div className={cn("w-full", currentStep === 0 ? "h-full" : "", animClass)}>
115→          {currentStep === 0 && <WelcomeStep onNext={goForward} />}
116→          {currentStep === 1 && <GitHubSetupStep onNext={goForward} onBack={goBack} />}
117→          {currentStep === 2 && <AIToolsCheckStep onNext={goForward} onBack={goBack} />}
118→          {currentStep === 3 && <ProjectSelectionStep onBack={goBack} onNext={goForward} />}
119→          {currentStep === 4 && <DeusStep onBack={goBack} onComplete={handleComplete} />}
120→        </div>
121→      </div>
122→    </div>
123→  );
124→}
