 64→function SidebarResizeHandle({
 65→  onSizeChange,
 66→  onDraggingChange,
 67→}: {
 68→  onSizeChange: (size: number | null) => void;
 69→  onDraggingChange: (dragging: boolean) => void;
 70→}) {
