 77→    mode: "primary",
 78→    minPrimarySize: 200,
 79→    minSecondarySize: 400,
 80→  });
 81→
 82→  // Notify parent of drag state changes to disable sidebar transitions
 83→  useEffect(() => {
 84→    onDraggingChange(isDragging);
 85→  }, [isDragging, onDraggingChange]);
 86→
 87→  if (!open) return null;
 88→
 89→  return <ResizeHandle handleProps={handleProps} isDragging={isDragging} label="Resize sidebar" />;
