  1→/**
  2→ * ServerLayout -- web mode shell for a connected server.
  3→ *
  4→ * Wraps routes under /s/$serverId. Handles:
  5→ * - Auth gate: shows PairGatePage for unauthenticated relay clients
  6→ * - Relay WebSocket connection with serverId for endpoint resolution
  7→ * - Connection state UI (connecting, offline, reconnecting)
  8→ *
  9→ * The auth gate renders BEFORE the WS connect hooks fire so we don't
 10→ * attempt a tokenless relay connection that would immediately fail.
 11→ */
 12→
 13→import { useEffect } from "react";
 14→import { Outlet, useParams } from "@tanstack/react-router";
 15→import { Toaster } from "@/components/ui/sonner";
 16→import { initNotifications } from "@/platform/notifications";
 17→import { useGlobalSessionNotifications } from "@/features/session/hooks/useGlobalSessionNotifications";
 18→import { useWorkspaceInitEvents } from "@/features/workspace/hooks/useWorkspaceInitEvents";
 19→import { useQueryProtocol } from "@/shared/hooks/useQueryProtocol";
 20→import { useBackendRestart } from "@/shared/hooks/useBackendRestart";
 21→import { useAnalyticsConsent } from "@/platform/analytics";
 22→import { useSettings } from "@/features/settings";
 23→import { useAuth, PairGatePage } from "@/features/auth";
 24→import { ServerOfflinePage } from "@/features/connection";
 25→import { isRelayMode } from "@/shared/config/backend.config";
 26→
 27→export function ServerLayout() {
 28→  // Extract serverId from route params for relay WS connection
 29→  const { serverId } = useParams({ strict: false }) as { serverId: string };
 30→
 31→  // Auth gate: relay mode requires device token authentication.
 32→  // This must be checked BEFORE mounting ServerContent, because
 33→  // ServerContent's useQueryProtocol will attempt a WS connect that
 34→  // requires a valid device token in relay mode.
 35→  const auth = useAuth();
 36→  const relay = isRelayMode();
 37→
 38→  // Request OS notification permission once on mount
 39→  useEffect(() => {
 40→    initNotifications();
 41→  }, []);
 42→
 43→  // Auth gate for relay mode: show pairing page if not authenticated
 44→  if (relay) {
 45→    if (auth.isLoading) {
 46→      return (
 47→        <div className="bg-background flex h-screen items-center justify-center">
 48→          <div className="text-muted-foreground text-sm">Checking authentication...</div>
 49→        </div>
 50→      );
 51→    }
 52→    if (!auth.isAuthenticated) {
 53→      return <PairGatePage onPaired={auth.onPaired} serverId={serverId} />;
 54→    }
 55→  }
 56→
 57→  // Auth passed (or not needed) — mount the connected content.
 58→  // ServerContent is a separate component so its hooks only run
 59→  // after the auth gate passes (hooks can't be conditional).
 60→  return <ServerContent serverId={serverId} />;
 61→}
 62→
 63→/**
 64→ * Inner component that runs all the WS + data hooks.
 65→ * Only mounted after the auth gate passes, ensuring we have
 66→ * a valid device token before attempting the relay WS connection.
 67→ */
 68→function ServerContent({ serverId }: { serverId: string }) {
 69→  const settingsQuery = useSettings();
 70→
 71→  // Global listeners -- same as DesktopShell
 72→  useGlobalSessionNotifications();
 73→  useWorkspaceInitEvents();
 74→
 75→  // Pass serverId so the WS URL resolves to the correct relay endpoint
 76→  useQueryProtocol(serverId);
 77→
 78→  useBackendRestart();
 79→  useAnalyticsConsent();
 80→
 81→  // While settings load, show a loading state
 82→  if (settingsQuery.isLoading) {
 83→    return (
 84→      <div className="bg-background flex h-screen items-center justify-center">
 85→        <div className="text-muted-foreground text-sm">Connecting...</div>
 86→      </div>
 87→    );
 88→  }
 89→
 90→  // Backend unreachable
 91→  if (settingsQuery.isError && !settingsQuery.data) {
 92→    return (
 93→      <ServerOfflinePage
 94→        onRetry={() => settingsQuery.refetch()}
 95→        variant={isRelayMode() ? "relay" : "desktop"}
 96→      />
 97→    );
 98→  }
 99→
100→  return (
101→    <>
102→      <Outlet />
103→      <Toaster />
104→    </>
105→  );
106→}
