 1→/**
 2→ * Shared error extraction utilities.
 3→ *
 4→ * Used across frontend, backend, and agent-server to safely extract information
 5→ * from `catch (err: unknown)` blocks without `any` casts.
 6→ */
 7→
 8→/**
 9→ * Safely extract an error message from any thrown value.
10→ */
11→export function getErrorMessage(err: unknown): string {
12→  if (err instanceof Error) return err.message;
13→  if (typeof err === "object" && err !== null && "message" in err) {
14→    return String((err as { message: unknown }).message);
15→  }
16→  return String(err);
17→}
18→
19→/**
20→ * Safely extract .code from a thrown value (e.g., Node.js ENOENT, EACCES).
21→ */
22→export function getErrorCode(err: unknown): string | undefined {
23→  if (typeof err === "object" && err !== null && "code" in err) {
24→    const code = (err as { code: unknown }).code;
25→    return typeof code === "string" ? code : undefined;
26→  }
27→  return undefined;
28→}
29→
30→export type ExecErrorLike = Error & {
31→  killed?: boolean;
32→  code?: string | number | null;
33→  stderr?: string;
34→  stdout?: string;
35→  status?: number | null;
36→};
37→
38→/**
39→ * Type guard for child_process exec/execFile errors.
40→ *
41→ * Node exposes slightly different shapes for async (`execFile`) vs sync
42→ * (`execFileSync`) failures, so the advertised properties are optional and
43→ * validated only when present.
44→ */
45→export function isExecError(err: unknown): err is ExecErrorLike {
46→  if (!(err instanceof Error)) return false;
47→
48→  const record = err as unknown as Record<string, unknown>;
49→  const hasExecFields = ["killed", "code", "stderr", "stdout", "status"].some(
50→    (key) => key in record
51→  );
52→  if (!hasExecFields) return false;
53→
54→  return (
55→    (!("killed" in record) || typeof record.killed === "boolean") &&
56→    (!("code" in record) ||
57→      typeof record.code === "string" ||
58→      typeof record.code === "number" ||
59→      record.code === null) &&
60→    (!("stderr" in record) || typeof record.stderr === "string") &&
61→    (!("stdout" in record) || typeof record.stdout === "string") &&
62→    (!("status" in record) || typeof record.status === "number" || record.status === null)
63→  );
64→}
